#!/usr/bin/env node
// WebGPU compat harness — runs a runtime-agnostic test snippet under Deno
// (oracle, expected) and monster (under test, actual) and diffs the
// `__RESULT__ <json>` line each prints. Exit 0 = match.
//
//   node run.mjs tests/01-adapter-device.mjs
//   node run.mjs --oracle-only tests/01-adapter-device.mjs   # capture oracle
import { spawnSync } from 'node:child_process';
import { existsSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const HERE = dirname(fileURLToPath(import.meta.url));
const REPO = resolve(HERE, '../../..');
const DENO = '/opt/homebrew/bin/deno';
// MONSTER_BIN lets the harness target a feature-built `gnexec` (webgpu) without
// touching the shared `bin/monster` other agents use.
const MONSTER = process.env.MONSTER_BIN || resolve(REPO, 'open-source/gnosis/bin/monster');

const args = process.argv.slice(2);
const oracleOnly = args.includes('--oracle-only');
const actualOnly = args.includes('--actual-only');
const test = resolve(process.cwd(), args.find((a) => !a.startsWith('--')));
if (!existsSync(test)) {
  console.error('test not found:', test);
  process.exit(2);
}

function extract(stdout) {
  const line = stdout.split('\n').find((l) => l.includes('__RESULT__'));
  if (!line) return { __error: 'no __RESULT__ line', raw: stdout.slice(-400) };
  try { return JSON.parse(line.slice(line.indexOf('__RESULT__') + 10).trim()); }
  catch (e) { return { __error: 'bad json: ' + e.message, raw: line }; }
}

function runOracle() {
  const r = spawnSync(DENO, ['run', '--allow-read', '--allow-env', test], { encoding: 'utf8' });
  return extract((r.stdout || '') + (r.stderr || ''));
}
function runActual() {
  const r = spawnSync(MONSTER, [test], { encoding: 'utf8', env: { ...process.env, GNEXEC_ALLOW_GPU: '1' } });
  return extract((r.stdout || '') + (r.stderr || ''));
}

const oracle = oracleOnly || !actualOnly ? runOracle() : null;
const actual = actualOnly || !oracleOnly ? runActual() : null;

console.log('ORACLE (deno):', JSON.stringify(oracle));
console.log('ACTUAL (monster):', JSON.stringify(actual));

// Canonicalize (recursively sort object keys) so key-order differences between
// runtimes don't read as mismatches — only values matter.
function canon(v) {
  if (Array.isArray(v)) return v.map(canon);
  if (v && typeof v === 'object') {
    return Object.fromEntries(Object.keys(v).sort().map((k) => [k, canon(v[k])]));
  }
  return v;
}
if (oracle && actual) {
  const match = JSON.stringify(canon(oracle)) === JSON.stringify(canon(actual));
  console.log(match ? '✅ MATCH' : '❌ MISMATCH');
  process.exit(match ? 0 : 1);
}
